{"file_path":"/home/user/workspace/app/admin/catalog/product-table.tsx","content":"import { unstable_cache } from "next/cache";
import { getAllProducts } from "@/lib/db";

/**
 * Cached product fetcher.
 *
 * Tagged with "products" so that the admin "Sync latest catalog" action
 * (which calls revalidateTag("products")) invalidates this cache entry.
 * The key ["catalog-products"] differentiates this from other consumers
 * that tag their data with the same "products" tag (e.g. a dashboard
 * widget) so they all invalidate together — "eventual consistency across
 * catalog views."
 */
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["catalog-products"],
  {
    tags: ["products"],
    /**
     * Fallback revalidation window (5 minutes) in case the explicit
     * sync trigger is not used — admins who just browse the catalog
     * will see data no older than this.
     */
    revalidate: 300,
  }
);

export async function ProductTable() {
  const products = await getCachedProducts();

  if (products.length === 0) {
    return <p className="empty-state">No products found.</p>;
  }

  return (
    <div className="table-wrapper">
      <table>
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Availability</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id} data-available={product.available}>
              <td className="sku">{product.sku}</td>
              <td>{product.name}</td>
              <td className="price">${product.price}</td>
              <td className="inventory">{product.inventory}</td>
              <td>
                <span
                  className={`badge ${
                    product.available ? "badge--available" : "badge--unavailable"
                  }`}
                >
                  {product.available ? "In Stock" : "Out of Stock"}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <p className="table-footer">
        Showing {products.length} product{products.length !== 1 ? "s" : ""}
      </p>
    </div>
  );
}
"}

