{"file_path":"/home/user/workspace/app/admin/catalog/page.tsx","content":"import { Suspense } from "react";
import { revalidateTag } from "next/cache";
import { redirect } from "next/navigation";
import { ProductTable } from "./product-table";

export const metadata = {
  title: "Product Catalog — Admin",
};

/**
 * Admin product catalog page.
 *
 * ── Caching ──────────────────────────────────────────────────────
 * Product data is cached under the "products" tag (see product-table.tsx).
 * The page is read-heavy by nature; caching avoids re-querying the
 * underlying data source on every request, keeping day-to-day browsing fast.
 *
 * ── Sync trigger ─────────────────────────────────────────────────
 * The form below fires the inline server action syncCatalog() which
 * invalidates all cache entries tagged "products".  Because tag
 * invalidation is a lightweight metadata operation the server action
 * returns almost instantly.  After the redirect the page shell renders
 * immediately; the product table (wrapped in <Suspense>) streams in
 * with fresh data a moment later — admins can keep working without
 * waiting for a full recompute.
 *
 *   "…eventual consistency across catalog views"
 *
 * Any other route that tags its data with "products" gets the same
 * cache-busting signal, so all views converge on the new data without
 * requiring a blocking sweep of every query.
 */
export default async function AdminCatalogPage({
  searchParams,
}: {
  searchParams: Promise<{ synced?: string }>;
}) {
  const { synced } = await searchParams;

  /**
   * Inline Server Action — the sync handler lives next to the form
   * that invokes it so the relationship is obvious when skimming the
   * file.
   */
  async function syncCatalog() {
    "use server";

    // 1. Invalidate every cache entry tagged "products"
    revalidateTag("products");

    // 2. Redirect with a query param so the page can display a
    //    confirmation banner without blocking on fresh data.
    redirect("/admin/catalog?synced=true");
  }

  return (
    <div className="catalog-page">
      <header className="catalog-header">
        <div>
          <h1>Product Catalog</h1>
          <p className="subtitle">
            Browse and manage your product catalogue. Data is cached for fast
            browsing — use the sync action below to refresh from the upstream
            ERP/PIM system.
          </p>
        </div>

        <form action={syncCatalog}>
          <button type="submit" className="btn btn--sync">
            Sync latest catalog
          </button>
        </form>
      </header>

      {synced === "true" && (
        <div className="banner banner--success" role="status">
          <svg
            width="20"
            height="20"
            viewBox="0 0 20 20"
            fill="none"
            aria-hidden="true"
          >
            <path
              d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.5 12.5l5-5"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
          <span>
            Catalog sync triggered. Product data is being refreshed —
            changes should appear across all catalog views momentarily.
          </span>
        </div>
      )}

      <Suspense
        fallback={
          <div className="table-skeleton" aria-busy="true">
            <div className="skeleton-row" />
            <div className="skeleton-row" />
            <div className="skeleton-row" />
            <div className="skeleton-row" />
            <div className="skeleton-row" />
          </div>
        }
      >
        <ProductTable />
      </Suspense>
    </div>
  );
}
"}

